class Solution:
    def maxTotalReward(self, rewardValues: List[int]) -> int:
        rewardValues.sort()
        n = len(rewardValues)
        dp = set()
        dp.add(0)

        for i in range(n):
            reward = rewardValues[i]
            new_dp = set()
            for x in dp:
                if x < reward:
                    new_dp.add(x + reward)
            dp |= new_dp

        return max(dp)
